/* ---- ui/form/slider.js ---- */
// aiditor.ui.slider — horizontal numeric slider with optional value bubble.
//
// opts: {
//   value: number|signal, onChange?,
//   min?: number|signal, max?: number|signal, step?: number|signal,
//   showValue?: boolean|signal, suffix?: string|signal,
// }
